import{_ as a,o,c as t,ag as i}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"Glosario","description":"Todos los términos de SYNTIweb explicados para dueños de negocio venezolanos","frontmatter":{"title":"Glosario","description":"Todos los términos de SYNTIweb explicados para dueños de negocio venezolanos"},"headers":[],"relativePath":"referencia/glosario.md","filePath":"referencia/glosario.md"}'),n={name:"referencia/glosario.md"};function r(l,e,s,d,c,u){return o(),t("div",null,[...e[0]||(e[0]=[i('<h2 id="terminos-generales" tabindex="-1">Términos generales <a class="header-anchor" href="#terminos-generales" aria-label="Permalink to &quot;Términos generales&quot;">​</a></h2><h3 id="syntiweb" tabindex="-1">SYNTIweb <a class="header-anchor" href="#syntiweb" aria-label="Permalink to &quot;SYNTIweb&quot;">​</a></h3><p>La plataforma completa. Incluye los 3 productos (SYNTIstudio, SYNTIfood, SYNTIcat), tu panel de administración y esta documentación. Vive en <code>syntiweb.com</code>.</p><h3 id="landing-landing-page" tabindex="-1">Landing / Landing page <a class="header-anchor" href="#landing-landing-page" aria-label="Permalink to &quot;Landing / Landing page&quot;">​</a></h3><p>Tu página web pública — lo que ven tus clientes cuando visitan <code>tunegocio.syntiweb.com</code>. No es tu panel de administración.</p><h3 id="tu-panel-panel-de-administracion" tabindex="-1">Tu panel / Panel de administración <a class="header-anchor" href="#tu-panel-panel-de-administracion" aria-label="Permalink to &quot;Tu panel / Panel de administración&quot;">​</a></h3><p>La interfaz flotante donde editas tu negocio. Se activa con <strong>Alt+S</strong> (escritorio) o manteniendo presionado el logo 3 segundos (móvil). Protegido por PIN de 4 dígitos.</p><h3 id="blueprint" tabindex="-1">Blueprint <a class="header-anchor" href="#blueprint" aria-label="Permalink to &quot;Blueprint&quot;">​</a></h3><p>El tipo de producto que elegiste: <code>studio</code> (web completa), <code>food</code> (menú digital) o <code>cat</code> (catálogo con carrito). Define qué secciones y funcionalidades tiene tu página.</p><h3 id="tenant" tabindex="-1">Tenant <a class="header-anchor" href="#tenant" aria-label="Permalink to &quot;Tenant&quot;">​</a></h3><p>Tu negocio dentro de la plataforma. Cada negocio registrado es un &quot;tenant&quot; — tiene su propio espacio, datos, imágenes y subdominio. Totalmente aislado de los demás.</p><h3 id="subdominio" tabindex="-1">Subdominio <a class="header-anchor" href="#subdominio" aria-label="Permalink to &quot;Subdominio&quot;">​</a></h3><p>Tu dirección web dentro de SYNTIweb. Ejemplo: <code>tunegocio.syntiweb.com</code>. Se elige una vez al crear el negocio y no se puede cambiar después.</p><hr><h2 id="terminos-de-precios-y-moneda" tabindex="-1">Términos de precios y moneda <a class="header-anchor" href="#terminos-de-precios-y-moneda" aria-label="Permalink to &quot;Términos de precios y moneda&quot;">​</a></h2><h3 id="ref" tabindex="-1">REF <a class="header-anchor" href="#ref" aria-label="Permalink to &quot;REF&quot;">​</a></h3><p>&quot;Referencia&quot; — el símbolo para mostrar precios en dólares. Ejemplo: REF 15.00. Se usa REF en lugar de $ por diseño. Es intercambiable con el símbolo $.</p><h3 id="tasa-bcv" tabindex="-1">Tasa BCV <a class="header-anchor" href="#tasa-bcv" aria-label="Permalink to &quot;Tasa BCV&quot;">​</a></h3><p>Tasa oficial de cambio del Banco Central de Venezuela. SYNTIweb la obtiene automáticamente para convertir precios de REF a bolívares.</p><h3 id="modo-de-moneda" tabindex="-1">Modo de moneda <a class="header-anchor" href="#modo-de-moneda" aria-label="Permalink to &quot;Modo de moneda&quot;">​</a></h3><p>Cómo se muestran los precios en tu landing. Hay 5 opciones:</p><ul><li><strong>Solo referencia</strong> (<code>reference_only</code>): Solo muestra REF/$</li><li><strong>Solo bolívares</strong> (<code>bolivares_only</code>): Solo muestra Bs.</li><li><strong>Ambos con toggle</strong> (<code>both_toggle</code>): REF y Bs. con botón para alternar (por defecto)</li><li><strong>Euro con toggle</strong> (<code>euro_toggle</code>): € y Bs. con toggle</li><li><strong>Ocultar</strong> (<code>hidden</code>): No muestra precios, solo &quot;Más Info&quot;</li></ul><hr><h2 id="terminos-de-tu-panel" tabindex="-1">Términos de tu panel <a class="header-anchor" href="#terminos-de-tu-panel" aria-label="Permalink to &quot;Términos de tu panel&quot;">​</a></h2><h3 id="tab-pestana" tabindex="-1">Tab / Pestaña <a class="header-anchor" href="#tab-pestana" aria-label="Permalink to &quot;Tab / Pestaña&quot;">​</a></h3><p>Cada pestaña del menú lateral de tu panel. Hay 7 tabs:</p><ol><li><strong>Tu Información</strong> — Datos del negocio, horario, redes sociales</li><li><strong>Qué Vendes</strong> — Productos y servicios</li><li><strong>Cómo Se Ve</strong> — Paleta de colores y tema visual</li><li><strong>Tu Mensaje</strong> — Orden de secciones, testimonios, FAQ, sucursales, CTA</li><li><strong>Pulso del Negocio</strong> — Analítica y estadísticas</li><li><strong>Visual</strong> — Variantes de secciones y efectos</li><li><strong>Configuración</strong> — Medios de pago, moneda, PIN, plan</li></ol><h3 id="pin" tabindex="-1">PIN <a class="header-anchor" href="#pin" aria-label="Permalink to &quot;PIN&quot;">​</a></h3><p>Código de 4 dígitos numéricos que protege el acceso a tu panel. Se establece al crear el negocio y se puede cambiar desde <strong>Configuración → PIN de Acceso</strong>.</p><h3 id="badge" tabindex="-1">Badge <a class="header-anchor" href="#badge" aria-label="Permalink to &quot;Badge&quot;">​</a></h3><p>Etiqueta visual que se muestra sobre un producto. Ejemplos:</p><ul><li><strong>SYNTIstudio</strong>: ⭐ Destacado, 🔥 Hot, ✨ New, 🎉 Promo</li><li><strong>SYNTIcat</strong>: 🆕 Nuevo, 🔥 Hot, 💰 Promo</li></ul><h3 id="paleta-de-color-tema" tabindex="-1">Paleta de color / Tema <a class="header-anchor" href="#paleta-de-color-tema" aria-label="Permalink to &quot;Paleta de color / Tema&quot;">​</a></h3><p>Esquema de colores que define la apariencia completa de tu sitio. Hay 30+ paletas prediseñadas organizadas por tipo de negocio. Se elige en la pestaña <strong>Cómo Se Ve</strong>.</p><h3 id="cta-call-to-action" tabindex="-1">CTA (Call to Action) <a class="header-anchor" href="#cta-call-to-action" aria-label="Permalink to &quot;CTA (Call to Action)&quot;">​</a></h3><p>&quot;Llamado a Acción&quot; — la sección de tu landing con un mensaje directo y botón que invita al cliente a contactarte por WhatsApp. Se configura en <strong>Tu Mensaje → CTA</strong>.</p><hr><h2 id="terminos-de-productos" tabindex="-1">Términos de productos <a class="header-anchor" href="#terminos-de-productos" aria-label="Permalink to &quot;Términos de productos&quot;">​</a></h2><h3 id="variante" tabindex="-1">Variante <a class="header-anchor" href="#variante" aria-label="Permalink to &quot;Variante&quot;">​</a></h3><p>Opción de producto como talla o color. Solo disponible en SYNTIcat (plan Semestral en adelante).</p><ul><li><code>size</code>: Solo talla (S, M, L, XL)</li><li><code>size_color</code>: Talla + color</li><li><code>options</code>: Opciones libres (extras, personalización)</li></ul><h3 id="categoria-syntifood" tabindex="-1">Categoría (SYNTIfood) <a class="header-anchor" href="#categoria-syntifood" aria-label="Permalink to &quot;Categoría (SYNTIfood)&quot;">​</a></h3><p>Agrupación de platos en el menú digital. Ejemplo: &quot;Arepas&quot;, &quot;Carnes&quot;, &quot;Bebidas&quot;. Cada categoría puede tener 1 foto representativa.</p><h3 id="item-syntifood" tabindex="-1">Ítem (SYNTIfood) <a class="header-anchor" href="#item-syntifood" aria-label="Permalink to &quot;Ítem (SYNTIfood)&quot;">​</a></h3><p>Un plato individual dentro de una categoría. Tiene nombre, descripción opcional y precio.</p><hr><h2 id="terminos-de-pedidos" tabindex="-1">Términos de pedidos <a class="header-anchor" href="#terminos-de-pedidos" aria-label="Permalink to &quot;Términos de pedidos&quot;">​</a></h2><h3 id="pedido-rapido-syntifood" tabindex="-1">Pedido Rápido (SYNTIfood) <a class="header-anchor" href="#pedido-rapido-syntifood" aria-label="Permalink to &quot;Pedido Rápido (SYNTIfood)&quot;">​</a></h3><p>Función que permite al cliente acumular platos con botones [+] y enviar todo como mensaje de WhatsApp. No es carrito — es un acumulador simple. Solo plan Anual.</p><h3 id="mini-order-sc-xxxx-synticat" tabindex="-1">Mini Order / SC-XXXX (SYNTIcat) <a class="header-anchor" href="#mini-order-sc-xxxx-synticat" aria-label="Permalink to &quot;Mini Order / SC-XXXX (SYNTIcat)&quot;">​</a></h3><p>Código de seguimiento que se genera al finalizar un pedido en SYNTIcat (plan Anual). Formato: SC-0001, SC-0002, etc. Se envía por WhatsApp junto con el detalle del pedido.</p><h3 id="cart-drawer-synticat" tabindex="-1">Cart Drawer (SYNTIcat) <a class="header-anchor" href="#cart-drawer-synticat" aria-label="Permalink to &quot;Cart Drawer (SYNTIcat)&quot;">​</a></h3><p>Panel lateral que se desliza desde la derecha mostrando el contenido del carrito de compras. Solo planes Semestral y Anual.</p><hr><h2 id="terminos-tecnicos" tabindex="-1">Términos técnicos <a class="header-anchor" href="#terminos-tecnicos" aria-label="Permalink to &quot;Términos técnicos&quot;">​</a></h2><h3 id="webp" tabindex="-1">WebP <a class="header-anchor" href="#webp" aria-label="Permalink to &quot;WebP&quot;">​</a></h3><p>Formato de imagen que usa SYNTIweb. Todas las fotos que subes se convierten automáticamente a WebP para que carguen más rápido. Máximo 800px de ancho, máximo 2MB.</p><h3 id="schema-org-seo" tabindex="-1">Schema.org (SEO) <a class="header-anchor" href="#schema-org-seo" aria-label="Permalink to &quot;Schema.org (SEO)&quot;">​</a></h3><p>Código estructurado que ayuda a Google a entender tu negocio. Se genera automáticamente según tu plan. En SYNTIstudio Visión incluye Schema completo + FAQ.</p><h3 id="qr" tabindex="-1">QR <a class="header-anchor" href="#qr" aria-label="Permalink to &quot;QR&quot;">​</a></h3><p>Código de barras cuadrado que, al escanearlo con el celular, abre tu página web. Lo descargas desde tu panel y lo imprimes como sticker para tu local.</p><h3 id="shortlink" tabindex="-1">Shortlink <a class="header-anchor" href="#shortlink" aria-label="Permalink to &quot;Shortlink&quot;">​</a></h3><p>URL corta asociada a tu QR para tracking. Ejemplo: <code>syntiweb.com/s/elcorte</code>.</p><h3 id="medios-de-pago" tabindex="-1">Medios de pago <a class="header-anchor" href="#medios-de-pago" aria-label="Permalink to &quot;Medios de pago&quot;">​</a></h3><p>Chips informativos que muestran qué métodos de pago acepta tu negocio. <strong>No son pasarela de pago</strong> — solo información visual para que tu cliente sepa cómo pagarte. Hay 11 nacionales (Pago Móvil, Punto de Venta, Biopago, etc.) y 7 internacionales (Zelle, PayPal, Binance Pay, etc.).</p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/referencia/preguntas-frecuentes.html">Preguntas frecuentes</a> — Respuestas a dudas comunes</li><li><a href="/shared/troubleshooting.html">Solución de problemas</a> — Cuando algo no funciona</li><li><a href="/primeros-pasos/que-es-syntiweb.html">¿Qué es SYNTIweb?</a> — Descripción general de la plataforma</li></ul>',67)])])}const h=a(n,[["render",r]]);export{m as __pageData,h as default};
